-- 006: backfill telefone on controle_tmb from TMB CSV export (pedido_id → phone).
-- The TMB webhook doesn't send phone, so historical rows have no phone. Export from
-- the TMB portal DOES include it, so we join on pedido_id and backfill.
-- Idempotent: only updates rows where telefone is NULL. Safe to re-run with newer CSVs.

ALTER TABLE uelicon_database.controle_tmb ADD COLUMN IF NOT EXISTS telefone text;

